for k: int := 1 to |stops|
  invariant forall i: int {:trigger result[i]} | 0 <= i < |result| :: forall m: int {:trigger stops[m]} | 0 <= m < k :: InSeq(result[i], stops[m])
  invariant forall x: int {:trigger InSeq(x, result)} :: (forall m: int {:trigger stops[m]} | 0 <= m < k :: InSeq(x, stops[m])) ==> InSeq(x, result)
{
  var newResult: seq<int> := [];
  for i: int := 0 to |result|
    invariant forall idx: int {:trigger newResult[idx]} | 0 <= idx < |newResult| :: InSeq(newResult[idx], stops[k]) && InSeq(newResult[idx], result)
    invariant forall idx: int {:trigger result[idx]} | 0 <= idx < i :: InSeq(result[idx], stops[k]) ==> InSeq(result[idx], newResult)
  {
    var found := false;
    for j: int := 0 to |stops[k]|
      invariant found <==> exists j': int {:trigger stops[k][j']} | 0 <= j' < j :: result[i] == stops[k][j']
    {
      if result[i] == stops[k][j] {
        found := true;
      }
    }
    if found {
      ghost var oldNR := newResult;
      newResult := newResult + [result[i]];
      forall idx: int | 0 <= idx < i + 1
        ensures InSeq(result[idx], stops[k]) ==> InSeq(result[idx], newResult)
      {
        if idx < i {
          if InSeq(result[idx], stops[k]) {
            assert InSeq(result[idx], oldNR);
            ghost var w :| 0 <= w < |oldNR| && oldNR[w] == result[idx];
          }
        } else {
          if InSeq(result[i], stops[k]) {
            assert InSeq(result[i], newResult);
          }
        }
      }
      forall idx: int | 0 <= idx < |oldNR|
        ensures InSeq(newResult[idx], stops[k]) && InSeq(newResult[idx], result)
      {
        assert newResult[idx] == oldNR[idx];
      }
    }
  }
  assert forall i: int {:trigger newResult[i]} | 0 <= i < |newResult| :: forall m: int {:trigger stops[m]} | 0 <= m < k + 1 :: InSeq(newResult[i], stops[m]) by {
    forall i: int | 0 <= i < |newResult|
      ensures forall m: int {:trigger stops[m]} | 0 <= m < k + 1 :: InSeq(newResult[i], stops[m])
    {
      assert InSeq(newResult[i], stops[k]);
      assert InSeq(newResult[i], result);
      ghost var ridx :| 0 <= ridx < |result| && result[ridx] == newResult[i];
      forall m: int | 0 <= m < k
        ensures InSeq(newResult[i], stops[m])
      {
        assert InSeq(result[ridx], stops[m]);
      }
    }
  }
  result := newResult;
}

